'use strict';

const _ = require('lodash');
const problemsData = require('../../data/problems.json');

/**
 * Service to handle problems retrieval and filtering.
 */
class ProblemsService {
  /**
   * Get problems filtered by difficulty, tags, and limited by count.
   * @param {Object} params - Filtering parameters.
   * @param {string|string[]} [params.tags] - Skill tags to filter by (case-insensitive, comma-separated or array).
   * @param {string} [params.difficulty] - Difficulty filter.
   * @param {number} [params.limit] - Limit number of results.
   * @returns {Object} - Object containing filtered problems and metadata.
   */
  static getProblems(params = {}) {
    let { tags, difficulty, limit } = params;

    // Normalize tags to array of lowercase strings
    let normalizedTags = [];
    if (tags) {
      if (_.isString(tags)) {
        normalizedTags = tags.split(',').map(t => t.trim().toLowerCase()).filter(t => t.length > 0);
      } else if (_.isArray(tags)) {
        normalizedTags = tags.map(t => String(t).trim().toLowerCase()).filter(t => t.length > 0);
      }
    }

    // Filter problems by difficulty if provided
    let filtered = problemsData;
    if (difficulty) {
      filtered = filtered.filter(p => p.difficulty === difficulty);
    }

    // Filter by tags if provided
    if (normalizedTags.length > 0) {
      filtered = filtered.filter(p => {
        if (!p.tags || !Array.isArray(p.tags)) return false;
        const problemTags = p.tags.map(t => t.toLowerCase());
        return normalizedTags.every(t => problemTags.includes(t));
      });
    }

    // Sort problems by stable criteria: difficulty asc, then id asc
    filtered = _.orderBy(filtered, ['difficulty', 'id'], ['asc', 'asc']);

    // Apply limit if provided
    if (_.isNumber(limit) && limit >= 0) {
      filtered = filtered.slice(0, limit);
    }

    // Compose metadata with normalized tags
    const metadata = {
      tags: normalizedTags.length > 0 ? normalizedTags : undefined,
      difficulty: difficulty || undefined,
      limit: limit || undefined,
      totalCount: filtered.length,
    };

    return { problems: filtered, metadata };
  }
}

module.exports = ProblemsService;
